module RefModule (  
    input clk,  
    input reset,  
    input enable,  
    output reg [31:0] count  
);  
  wire _tap_clk = clk & {1{1'b1}};

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            count <= 32'd0;  
        end else if (enable) begin  
            count <= count + 1;  
        end  
    end  
endmodule
